--
-- TOC entry 383 (class 1255 OID 16387)
-- Name: get_auth(text); Type: FUNCTION; Schema: pgbouncer; Owner: supabase_admin
--

CREATE FUNCTION pgbouncer.get_auth(p_usename text) RETURNS TABLE(username text, password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $_$
  BEGIN
      RAISE DEBUG 'PgBouncer auth request: %', p_usename;

      RETURN QUERY
      SELECT
          rolname::text,
          CASE WHEN rolvaliduntil < now()
              THEN null
              ELSE rolpassword::text
          END
      FROM pg_authid
      WHERE rolname=$1 and rolcanlogin;
  END;
  $_$;


ALTER FUNCTION pgbouncer.get_auth(p_usename text) OWNER TO supabase_admin;

--
-- TOC entry 490 (class 1255 OID 17630)
-- Name: check_appointment_overlap(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_appointment_overlap() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    new_start_time TIMESTAMPTZ;
    overlap_exists BOOLEAN;
BEGIN
    SELECT start_time INTO new_start_time FROM timeslots WHERE id = NEW.timeslot_id;
    SELECT EXISTS (
        SELECT 1 FROM appointments a JOIN timeslots t ON a.timeslot_id = t.id
        WHERE a.requester_id = NEW.requester_id AND a.status = 'active'
        AND t.start_time = new_start_time AND a.id != NEW.id
    ) INTO overlap_exists;
    IF overlap_exists THEN
        RAISE EXCEPTION 'Choque de horários: Você já possui um agendamento ativo para este mesmo horário em outro setor.';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.check_appointment_overlap() OWNER TO postgres;

