-- Name: handle_appointment_cancel(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.handle_appointment_cancel() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF OLD.status = 'active' AND NEW.status = 'cancelled' THEN
    UPDATE public.timeslots SET is_available = true WHERE id = NEW.timeslot_id;
  END IF;
  RETURN NEW;
END;
$$;


