--
-- TOC entry 491 (class 1255 OID 17631)
-- Name: process_appointment_notifications(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.process_appointment_notifications() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' AND OLD.status IS DISTINCT FROM NEW.status THEN
    IF NEW.status = 'cancelled' THEN
      INSERT INTO public.notifications (user_id, title, message, is_read)
      VALUES (NEW.requester_id, 'Agendamento Cancelado', COALESCE('Motivo: ' || NEW.cancel_reason, 'O seu agendamento foi cancelado pelo setor.'), false);
    ELSIF NEW.status = 'completed' THEN
      INSERT INTO public.notifications (user_id, title, message, is_read)
      VALUES (NEW.requester_id, 'Agendamento Concluído', 'O setor registrou o desfecho do seu agendamento. Por favor, deixe sua avaliação.', false);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.process_appointment_notifications() OWNER TO postgres;

